const { renderComponent } = getComponentRenderer(getComponent);

const TEST_DEVFILE_ID = 'test-devfile-1';
const TEST_NAMESPACE = 'user-che';

describe('DevfileDetails Container', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  it('should render the DevfileDetails page when devfile exists', () => {
    const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
    const store = buildStore({ devfiles });
    renderComponent(store);

    expect(screen.getByTestId('devfile-details-page')).toBeInTheDocument();
    expect(screen.getByTestId('devfile-name')).toHaveTextContent('My Devfile');
  });

  it('should render Fallback when devfile is not found and loading', () => {
    const store = buildStore({ devfiles: [], isLoading: true });
    renderComponent(store);

    expect(screen.queryByTestId('devfile-details-page')).not.toBeInTheDocument();
  });

  it('should render Fallback when devfile is not found and no devfiles loaded', () => {
    const store = buildStore({ devfiles: [] });
    renderComponent(store);

    expect(screen.queryByTestId('devfile-details-page')).not.toBeInTheDocument();
  });

  it('should request devfiles on mount when store is empty', () => {
    const store = buildStore({ devfiles: [] });
    renderComponent(store);

    expect(mockRequestDevfiles).toHaveBeenCalledTimes(1);
  });

  it('should not request devfiles on mount when store has devfiles', () => {
    const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
    const store = buildStore({ devfiles });
    renderComponent(store);

    expect(mockRequestDevfiles).not.toHaveBeenCalled();
  });

  it('should request devfile schema on mount when schema is not loaded', () => {
    const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
    const store = buildStore({ devfiles, devfileSchema: undefined });
    renderComponent(store);

    expect(mockRequestDevfileSchema).toHaveBeenCalledTimes(1);
  });

  it('should subscribe to ConfigMap changes on mount', () => {
    const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
    const store = buildStore({ devfiles });
    renderComponent(store);

    expect(mockSubscribeToConfigMapChanges).toHaveBeenCalledTimes(1);
  });

  it('should pass namespace to the page component', () => {
    const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
    const store = buildStore({ devfiles });
    renderComponent(store);

    expect(screen.getByTestId('namespace')).toHaveTextContent(TEST_NAMESPACE);
  });

  it('should pass isLoading from the store', () => {
    const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
    const store = buildStore({ devfiles, isLoading: true });
    renderComponent(store);

    expect(screen.getByTestId('is-loading')).toHaveTextContent('true');
  });

  it('should pass isDarkTheme as false by default', () => {
    const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
    const store = buildStore({ devfiles });
    renderComponent(store);

    expect(screen.getByTestId('is-dark-theme')).toHaveTextContent('false');
  });

  describe('agent integration', () => {
    const testAgent: api.AiAgentDefinition = {
      id: 'test-agent',
      name: 'Test Agent',
      publisher: 'test-publisher',
      description: 'A test agent',
      icon: '',
      docsUrl: '',
      image: 'test-image',
      tag: 'latest',
      memoryLimit: '512Mi',
      cpuLimit: '500m',
      terminalPort: 8080,
      env: [],
      initCommand: '/bin/start',
    };

    it('should pass agentEnabled as true when agents are configured', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const store = buildStore({ devfiles, agents: [testAgent], defaultAgentId: 'test-agent' });
      renderComponent(store);

      expect(screen.getByTestId('agent-enabled')).toHaveTextContent('true');
    });

    it('should pass agentEnabled as false when no agents are configured', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const store = buildStore({ devfiles, agents: [], defaultAgentId: '' });
      renderComponent(store);

      expect(screen.getByTestId('agent-enabled')).toHaveTextContent('false');
    });

    it('should pass agent name and description from default agent', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const store = buildStore({ devfiles, agents: [testAgent], defaultAgentId: 'test-agent' });
      renderComponent(store);

      expect(screen.getByTestId('agent-name')).toHaveTextContent('Test Agent');
      expect(screen.getByTestId('agent-description')).toHaveTextContent('A test agent');
    });

    it('should pass agentInitCommand from default agent', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const store = buildStore({ devfiles, agents: [testAgent], defaultAgentId: 'test-agent' });
      renderComponent(store);

      expect(screen.getByTestId('agent-init-command')).toHaveTextContent('/bin/start');
    });

    it('should pass agentPodStatus when agent pod is present', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const agentPodStatuses: AgentPodStatus[] = [
        {
          agentId: 'test-agent-abc123',
          name: 'agent-pod-1',
          phase: AgentPodPhase.RUNNING,
          ready: true,
          serviceUrl: undefined,
        },
      ];
      const store = buildStore({
        devfiles,
        agents: [testAgent],
        defaultAgentId: 'test-agent',
        agentPodStatuses,
      });
      renderComponent(store);

      // The agentInstanceId is computed from defaultAgent.id + location hash,
      // so it won't match 'test-agent-abc123' in the mock; agentPodStatus should be undefined
      expect(screen.queryByTestId('agent-pod-phase')).not.toBeInTheDocument();
    });

    it('should pass agentTerminalUrl when available', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const store = buildStore({
        devfiles,
        agentTerminalUrl: 'http://localhost:8080/terminal',
      });
      renderComponent(store);

      expect(screen.getByTestId('agent-terminal-url')).toHaveTextContent(
        'http://localhost:8080/terminal',
      );
    });

    it('should not show agent terminal url when not available', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const store = buildStore({ devfiles, agentTerminalUrl: undefined });
      renderComponent(store);

      expect(screen.queryByTestId('agent-terminal-url')).not.toBeInTheDocument();
    });
  });

  describe('loading state with agent transitioning', () => {
    it('should show isLoading false when not loading and no agent transition', () => {
      const devfiles = [createTestDevfile(TEST_DEVFILE_ID, 'My Devfile')];
      const store = buildStore({ devfiles, isLoading: false });
      renderComponent(store);

      expect(screen.getByTestId('is-loading')).toHaveTextContent('false');
    });
  });

  describe('with multiple devfiles in the store', () => {
    it('should find the correct devfile by id', () => {
      const devfiles = [
        createTestDevfile('devfile-a', 'Devfile A'),
        createTestDevfile(TEST_DEVFILE_ID, 'Target Devfile'),
        createTestDevfile('devfile-c', 'Devfile C'),
      ];
      const store = buildStore({ devfiles });
      renderComponent(store);

      expect(screen.getByTestId('devfile-name')).toHaveTextContent('Target Devfile');
    });
  });
});

function createTestDevfile(id: string, name: string): LocalDevfile {
  return {
    id,
    name,
    description: `Description of ${name}`,
    content: `schemaVersion: 2.2.2\nmetadata:\n  name: ${name}`,
    projectNames: [],
    lastModified: new Date().toISOString(),
  };
}

function buildStore(
  options: {
    devfiles?: LocalDevfile[];
    isLoading?: boolean;
    devfileSchema?: DevfileSchema;
    agents?: api.AiAgentDefinition[];
    defaultAgentId?: string;
    agentPodStatuses?: AgentPodStatus[];
    agentTerminalUrl?: string;
  } = {},
): Store {
  const {
    devfiles = [],
    isLoading = false,
    devfileSchema,
    agents = [],
    defaultAgentId = '',
    agentPodStatuses = [],
    agentTerminalUrl,
  } = options;

  const localDevfilesState: LocalDevfilesState = {
    devfiles,
    isLoading,
    error: undefined,
    agentTerminalUrl,
    agentPodStatuses,
    configMapResourceVersion: '',
  };

  return new MockStoreBuilder({
    localDevfiles: localDevfilesState,
    devfileSchema: {
      isLoading: false,
      schema: devfileSchema,
    },
    aiAgentRegistry: {
      isLoading: false,
      agents,
      defaultAgentId,
    },
  })
    .withInfrastructureNamespace(
      [{ name: TEST_NAMESPACE, attributes: { default: 'true', phase: 'Active' } }],
      false,
    )
    .build();
}

function getComponent(store: Store): React.ReactElement {
  const devfileIdEncoded = encodeURIComponent(TEST_DEVFILE_ID);
  return (
    <Provider store={store}>
      <MemoryRouter initialEntries={[`/devfiles/${TEST_NAMESPACE}/${devfileIdEncoded}`]}>
        <Routes>
          <Route path="/devfiles/:namespace/:devfileId" element={<DevfileDetailsContainer />} />
        </Routes>
      </MemoryRouter>
    </Provider>
  );
}
